class Solution:
    def superEggDrop(self, k: int, n: int) -> int:
        dp = [[0] * (n + 1) for _ in range(k + 1)]
        for i in range(1, k + 1):
            dp[i][1] = 1
            dp[i][0] = 0
        for j in range(1, n + 1):
            dp[1][j] = j
        for i in range(2, k + 1):
            for j in range(2, n + 1):
                dp[i][j] = 1 + max(dp[i - 1][j - 1], dp[i][j - 1], dp[i - 1][j])
        return dp[k][n]
